class Solution {
    public boolean makeStringsEqual(String s, String target) {
        int n = s.length();
        for (int i = 0; i < n; i++) {
            if (s.charAt(i) == target.charAt(i)) {
                return true;
            }
        }
        return false;
    }
}
```

